<template>
	<view class="u-keyboard" @touchmove.stop.prevent="() => {}">
		<view class="u-keyboard-grids">
			<block>
				<view class="u-keyboard-grids-item" v-for="(group, i) in abc ? EngKeyBoardList : areaList" :key="i">
					<view :hover-stay-time="100" @tap="carInputClick(i, j)" hover-class="u-carinput-hover" class="u-keyboard-grids-btn"
					 v-for="(item, j) in group" :key="j">
						{{ item }}
					</view>
				</view>
				<view @touchstart="backspaceClick" @touchend="clearTimer" :hover-stay-time="100" class="u-keyboard-back"
				 hover-class="u-hover-class">
					<u-icon :size="38" name="backspace" :bold="true"></u-icon>
				</view>
				<view :hover-stay-time="100" class="u-keyboard-change" hover-class="u-carinput-hover" @tap="changeCarInputMode">
					<text class="zh" :class="[!abc ? 'active' : 'inactive']">õĖŁ</text>
					/
					<text class="en" :class="[abc ? 'active' : 'inactive']">Ķŗ▒</text>
				</view>
			</block>
		</view>
	</view>
</template>

<script>
	export default {
		name: "u-keyboard",
		props: {
			// µś»ÕÉ”µēōõ╣▒ķö«ńøśµīēķö«ńÜäķĪ║Õ║Å
			random: {
				type: Boolean,
				default: false
			}
		},
		data() {
			return {
				// ĶĮ”ńēīĶŠōÕģźµŚČ’╝īabc=trueõĖ║ĶŠōÕģźĶĮ”ńēīÕÅĘńĀü’╝ībac=falseõĖ║ĶŠōÕģźń£üõ╗ĮõĖŁµ¢ćń«Ćń¦░
				abc: false
			};
		},
		computed: {
			areaList() {
				let data = [
					'õ║¼',
					'µ▓¬',
					'ń▓ż',
					'µ┤ź',
					'ÕåĆ',
					'Ķ▒½',
					'õ║æ',
					'ĶŠĮ',
					'ķ╗æ',
					'µ╣ś',
					'ńÜ¢',
					'ķ▓ü',
					'ĶŗÅ',
					'µĄÖ',
					'ĶĄŻ',
					'ķäé',
					'µĪé',
					'ńöś',
					'µÖŗ',
					'ķÖĢ',
					'ĶÆÖ',
					'ÕÉē',
					'ķŚĮ',
					'Ķ┤Ą',
					'µĖØ',
					'ÕĘØ',
					'ķØÆ',
					'ńÉ╝',
					'Õ«ü',
					'µīé',
					'ĶŚÅ',
					'µĖ»',
					'µŠ│',
					'µ¢░',
					'õĮ┐',
					'ÕŁ”'
				];
				let tmp = [];
				// µēōõ╣▒ķĪ║Õ║Å
				if (this.random) data = this.$u.randomArray(data);
				// ÕłćÕē▓µłÉõ║īń╗┤µĢ░ń╗ä
				tmp[0] = data.slice(0, 10);
				tmp[1] = data.slice(10, 20);
				tmp[2] = data.slice(20, 30);
				tmp[3] = data.slice(30, 36);
				return tmp;
			},
			EngKeyBoardList() {
				let data = [
					1,
					2,
					3,
					4,
					5,
					6,
					7,
					8,
					9,
					0,
					'Q',
					'W',
					'E',
					'R',
					'T',
					'Y',
					'U',
					'I',
					'O',
					'P',
					'A',
					'S',
					'D',
					'F',
					'G',
					'H',
					'J',
					'K',
					'L',
					'Z',
					'X',
					'C',
					'V',
					'B',
					'N',
					'M'
				];
				let tmp = [];
				if (this.random) data = this.$u.randomArray(data);
				tmp[0] = data.slice(0, 10);
				tmp[1] = data.slice(10, 20);
				tmp[2] = data.slice(20, 30);
				tmp[3] = data.slice(30, 36);
				return tmp;
			}
		},
		methods: {
			// ńé╣Õć╗ķö«ńøśµīēķÆ«
			carInputClick(i, j) {
				let value = '';
				// õĖŹÕÉīµ©ĪÕ╝Å’╝īĶÄĘÕÅ¢õĖŹÕÉīµĢ░ń╗äńÜäÕĆ╝
				if (this.abc) value = this.EngKeyBoardList[i][j];
				else value = this.areaList[i][j];
				this.$emit('change', value);
			},
			// õ┐«µö╣µ▒ĮĶĮ”ńēīķö«ńøśńÜäĶŠōÕģźµ©ĪÕ╝Å’╝īõĖŁµ¢ć|Ķŗ▒µ¢ć
			changeCarInputMode() {
				this.abc = !this.abc;
			},
			// ńé╣Õć╗ķĆĆµĀ╝ķö«
			backspaceClick() {
				this.$emit('backspace');
				clearInterval(this.timer); //ÕåŹµ¼ĪµĖģń®║Õ«ÜµŚČÕÖ©’╝īķś▓µŁóķćŹÕżŹµ│©ÕåīÕ«ÜµŚČÕÖ©
				this.timer = null;
				this.timer = setInterval(() => {
					this.$emit('backspace');
				}, 250);
			},
			clearTimer() {
				clearInterval(this.timer);
				this.timer = null;
			},
		}
	};
</script>

<style lang="scss" scoped>
	@import "../../libs/css/style.components.scss";

	.u-keyboard-grids {
		background: rgb(215, 215, 217);
		padding: 24rpx 0;
		position: relative;
	}

	.u-keyboard-grids-item {
		@include vue-flex;
		align-items: center;
		justify-content: center;
	}

	.u-keyboard-grids-btn {
		text-decoration: none;
		width: 62rpx;
		flex: 0 0 64rpx;
		height: 80rpx;
		/* #ifndef APP-NVUE */
		display: inline-flex;		
		/* #endif */
		font-size: 36rpx;
		text-align: center;
		line-height: 80rpx;
		background-color: #fff;
		margin: 8rpx 5rpx;
		border-radius: 8rpx;
		box-shadow: 0 2rpx 0rpx #888992;
		font-weight: 500;
		justify-content: center;
	}

	.u-carinput-hover {
		background-color: rgb(185, 188, 195) !important;
	}

	.u-keyboard-back {
		position: absolute;
		width: 96rpx;
		right: 22rpx;
		bottom: 32rpx;
		height: 80rpx;
		background-color: rgb(185, 188, 195);
		@include vue-flex;
		align-items: center;
		border-radius: 8rpx;
		justify-content: center;
		box-shadow: 0 2rpx 0rpx #888992;
	}

	.u-keyboard-change {
		font-size: 24rpx;
		box-shadow: 0 2rpx 0rpx #888992;
		position: absolute;
		width: 96rpx;
		left: 22rpx;
		line-height: 1;
		bottom: 32rpx;
		height: 80rpx;
		background-color: #ffffff;
		@include vue-flex;
		align-items: center;
		border-radius: 8rpx;
		justify-content: center;
	}

	.u-keyboard-change .inactive.zh {
		transform: scale(0.85) translateY(-10rpx);
	}

	.u-keyboard-change .inactive.en {
		transform: scale(0.85) translateY(10rpx);
	}

	.u-keyboard-change .active {
		color: rgb(237, 112, 64);
		font-size: 30rpx;
	}

	.u-keyboard-change .zh {
		transform: translateY(-10rpx);
	}

	.u-keyboard-change .en {
		transform: translateY(10rpx);
	}
</style>
